from dataclasses import dataclass, field

@dataclass
class Pedido:
    producto: str
    precio: float
    es_costoso: bool = field(init=False)

    def __post_init__(self):
        self.es_costoso = self.precio > 100

def evaluar_pedido(producto, precio):
    p = Pedido(producto, precio)
    return p.es_costoso

