class Producto:
    __slots__ = ('_nombre', '_precio')
    def __init__(self, nombre, precio):
        self._nombre = nombre
        self.precio = precio

    @property
    def precio(self):
        return self._precio

    @precio.setter
    def precio(self, valor):
        self._precio = valor if valor >= 0 else 0

    @property
    def impuesto(self):
        return self._precio * 0.10

def obtener_datos_producto(nombre, valor):
    p = Producto(nombre, valor)
    return (p.precio, p.impuesto)

