class SaldoInsuficienteError(Exception):
    pass

def realizar_retiro(saldo_actual, monto_a_retirar):
    if monto_a_retirar <= 0:
        raise ValueError("Monto inválido")
    if monto_a_retirar > saldo_actual:
        raise SaldoInsuficienteError("Fondos insuficientes")
    return saldo_actual - monto_a_retirar

